import React, { useState } from 'react';
import '../index.css';

function CreateCapsule() {
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');
  const [message, setMessage] = useState('');
  const [image, setImage] = useState(null);
  const [video, setVideo] = useState(null);
  const [audio, setAudio] = useState(null);

  const handleFileChange = (event, setFile) => {
    setFile(event.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    formData.append("title", title);
    formData.append("date", date);
    formData.append("message", message);
    if (image) formData.append("image", image);
    if (video) formData.append("video", video);
    if (audio) formData.append("audio", audio);

    await fetch("http://localhost:5000/api/capsules", {
      method: "POST",
      body: formData,
    });
  };

  return (
    <div>
      <h1>Create a Time Capsule</h1>

      <form className="form-container" onSubmit={handleSubmit}>
        <input type="text" placeholder="Title" value={title} onChange={(e) => setTitle(e.target.value)} required />
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)} required />
        <textarea placeholder="Write your message..." value={message} onChange={(e) => setMessage(e.target.value)} required></textarea>

        <input type="file" accept="image/*" onChange={(e) => handleFileChange(e, setImage)} />
        <input type="file" accept="video/*" onChange={(e) => handleFileChange(e, setVideo)} />
        <input type="file" accept="audio/*" onChange={(e) => handleFileChange(e, setAudio)} />

        <button type="submit">Create Capsule</button>
      </form>
    </div>
  );
}

export default CreateCapsule;
